-- KB-3 PostgreSQL Database Schema\n-- Complete database structure for guideline evidence system with conflict resolution\n\n-- Create schema for KB-3\nCREATE SCHEMA IF NOT EXISTS guideline_evidence;\nSET search_path TO guideline_evidence;\n\n-- Enable UUID extension\nCREATE EXTENSION IF NOT EXISTS \"uuid-ossp\";\nCREATE EXTENSION IF NOT EXISTS \"pg_crypto\";\n\n-- =============================================================================\n-- CORE TABLES\n-- =============================================================================\n\n-- Guidelines metadata with comprehensive tracking\nCREATE TABLE guidelines (\n    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n    guideline_id VARCHAR(100) UNIQUE NOT NULL,\n    organization VARCHAR(100) NOT NULL,\n    title TEXT NOT NULL,\n    region VARCHAR(20) NOT NULL,\n    condition_primary VARCHAR(200) NOT NULL,\n    icd10_codes TEXT[] NOT NULL,\n    version VARCHAR(50) NOT NULL,\n    \n    -- Temporal tracking\n    effective_date DATE NOT NULL,\n    superseded_date DATE,\n    supersedes VARCHAR(100),\n    \n    -- Evidence and quality\n    evidence_summary JSONB NOT NULL,\n    quality_metrics JSONB NOT NULL,\n    publication_source TEXT,\n    doi VARCHAR(100),\n    \n    -- Status management\n    status VARCHAR(20) DEFAULT 'draft' CHECK (status IN ('draft', 'pending', 'active', 'superseded', 'withdrawn')),\n    approval_status VARCHAR(20) DEFAULT 'pending' CHECK (approval_status IN ('pending', 'approved', 'rejected')),\n    \n    -- Audit and integrity\n    created_at TIMESTAMPTZ DEFAULT NOW(),\n    updated_at TIMESTAMPTZ DEFAULT NOW(),\n    created_by VARCHAR(100),\n    approved_by VARCHAR(100),\n    approval_date TIMESTAMPTZ,\n    digital_signature TEXT,\n    \n    -- Clinical review requirements\n    requires_clinical_review BOOLEAN DEFAULT TRUE,\n    medical_director_approval BOOLEAN DEFAULT FALSE,\n    clinical_committee_review BOOLEAN DEFAULT FALSE\n);\n\n-- Create indexes for performance\nCREATE INDEX idx_guidelines_region ON guidelines(region);\nCREATE INDEX idx_guidelines_condition ON guidelines(condition_primary);\nCREATE INDEX idx_guidelines_status ON guidelines(status, approval_status);\nCREATE INDEX idx_guidelines_effective_date ON guidelines(effective_date DESC);\nCREATE INDEX idx_guidelines_icd10 ON guidelines USING GIN(icd10_codes);\n\n-- =============================================================================\n-- CONFLICT MANAGEMENT\n-- =============================================================================\n\n-- Conflict resolution audit log\nCREATE TABLE conflict_resolutions (\n    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n    transaction_id VARCHAR(100) NOT NULL,\n    conflict_id VARCHAR(200) NOT NULL,\n    timestamp TIMESTAMPTZ DEFAULT NOW(),\n    \n    -- Conflicting guidelines\n    guideline_1_id VARCHAR(100) NOT NULL,\n    guideline_2_id VARCHAR(100) NOT NULL,\n    recommendation_1_id VARCHAR(100),\n    recommendation_2_id VARCHAR(100),\n    \n    -- Conflict details\n    conflict_type VARCHAR(50) NOT NULL CHECK (conflict_type IN (\n        'direct_contradiction', 'evidence_disagreement', \n        'population_overlap', 'target_difference'\n    )),\n    severity VARCHAR(20) NOT NULL CHECK (severity IN ('critical', 'major', 'minor')),\n    \n    -- Resolution details\n    resolution_rule VARCHAR(50) NOT NULL,\n    winning_guideline VARCHAR(100),\n    winning_recommendation VARCHAR(100),\n    rationale TEXT NOT NULL,\n    confidence_score INTEGER CHECK (confidence_score >= 0 AND confidence_score <= 100),\n    safety_override BOOLEAN DEFAULT FALSE,\n    \n    -- Context\n    patient_factors JSONB,\n    clinical_context JSONB,\n    \n    -- Audit and integrity\n    resolver_version VARCHAR(20),\n    resolved_by VARCHAR(100),\n    signed BOOLEAN DEFAULT FALSE,\n    checksum VARCHAR(64),\n    \n    -- Review and appeal\n    requires_review BOOLEAN DEFAULT FALSE,\n    reviewed_by VARCHAR(100),\n    review_date TIMESTAMPTZ,\n    appeal_filed BOOLEAN DEFAULT FALSE,\n    appeal_outcome VARCHAR(50)\n);\n\nCREATE INDEX idx_conflict_timestamp ON conflict_resolutions(timestamp DESC);\nCREATE INDEX idx_conflict_guidelines ON conflict_resolutions(guideline_1_id, guideline_2_id);\nCREATE INDEX idx_conflict_type ON conflict_resolutions(conflict_type, severity);\nCREATE INDEX idx_conflict_resolution_rule ON conflict_resolutions(resolution_rule);\n\n-- =============================================================================\n-- SAFETY OVERRIDE SYSTEM\n-- =============================================================================\n\n-- Safety overrides configuration\nCREATE TABLE safety_overrides (\n    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n    override_id VARCHAR(100) UNIQUE NOT NULL CHECK (override_id ~ '^SAFETY-[0-9]{3}$'),\n    priority INTEGER NOT NULL CHECK (priority >= 1 AND priority <= 10),\n    \n    -- Override definition\n    condition VARCHAR(200) NOT NULL,\n    description TEXT NOT NULL,\n    \n    -- Trigger conditions (stored as JSONB for flexibility)\n    trigger_conditions JSONB NOT NULL,\n    \n    -- Override action\n    override_action JSONB NOT NULL,\n    affected_guidelines TEXT[] NOT NULL,\n    \n    -- Status and control\n    active BOOLEAN DEFAULT TRUE,\n    requires_audit BOOLEAN DEFAULT TRUE,\n    \n    -- Governance\n    created_at TIMESTAMPTZ DEFAULT NOW(),\n    created_by VARCHAR(100),\n    approved_by VARCHAR(100),\n    approval_date TIMESTAMPTZ,\n    last_reviewed TIMESTAMPTZ,\n    next_review_date TIMESTAMPTZ,\n    \n    -- Clinical validation\n    clinical_validation_status VARCHAR(20) DEFAULT 'pending',\n    medical_director_approved BOOLEAN DEFAULT FALSE,\n    safety_committee_approved BOOLEAN DEFAULT FALSE\n);\n\nCREATE INDEX idx_safety_priority ON safety_overrides(priority ASC);\nCREATE INDEX idx_safety_condition ON safety_overrides(condition);\nCREATE INDEX idx_safety_active ON safety_overrides(active) WHERE active = TRUE;\nCREATE INDEX idx_safety_trigger_conditions ON safety_overrides USING GIN(trigger_conditions);\n\n-- Safety override application audit\nCREATE TABLE safety_override_audit (\n    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n    override_id VARCHAR(100) NOT NULL,\n    application_id VARCHAR(200) NOT NULL,\n    applied_at TIMESTAMPTZ DEFAULT NOW(),\n    \n    -- Patient context (anonymized)\n    patient_context JSONB NOT NULL,\n    \n    -- Action details\n    action_taken JSONB NOT NULL,\n    rationale TEXT NOT NULL,\n    requires_immediate_action BOOLEAN DEFAULT FALSE,\n    \n    -- Emergency tracking\n    emergency_protocol_activated BOOLEAN DEFAULT FALSE,\n    notifications_sent TEXT[],\n    escalation_level INTEGER DEFAULT 0,\n    \n    -- Audit integrity\n    engine_version VARCHAR(20),\n    checksum VARCHAR(64),\n    digital_signature TEXT,\n    \n    -- Outcome tracking\n    clinical_outcome VARCHAR(100),\n    outcome_notes TEXT,\n    follow_up_required BOOLEAN DEFAULT FALSE,\n    \n    FOREIGN KEY (override_id) REFERENCES safety_overrides(override_id)\n);\n\nCREATE INDEX idx_safety_audit_applied_at ON safety_override_audit(applied_at DESC);\nCREATE INDEX idx_safety_audit_override_id ON safety_override_audit(override_id);\nCREATE INDEX idx_safety_audit_emergency ON safety_override_audit(emergency_protocol_activated) WHERE emergency_protocol_activated = TRUE;\n\n-- =============================================================================\n-- VERSION MANAGEMENT\n-- =============================================================================\n\n-- Guideline version transitions and change tracking\nCREATE TABLE guideline_transitions (\n    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n    transition_id VARCHAR(200) UNIQUE NOT NULL,\n    \n    -- Version information\n    old_guideline_id VARCHAR(100),\n    new_guideline_id VARCHAR(100) NOT NULL,\n    transition_date DATE NOT NULL,\n    \n    -- Change analysis\n    change_type VARCHAR(20) NOT NULL CHECK (change_type IN ('major', 'minor', 'patch', 'emergency')),\n    major_changes JSONB NOT NULL,\n    clinical_impact_score INTEGER CHECK (clinical_impact_score >= 0 AND clinical_impact_score <= 100),\n    affected_populations TEXT[],\n    affected_domains TEXT[],\n    \n    -- Transition management\n    requires_notification BOOLEAN DEFAULT FALSE,\n    requires_training BOOLEAN DEFAULT FALSE,\n    requires_system_update BOOLEAN DEFAULT FALSE,\n    \n    -- Migration strategy\n    transition_period_days INTEGER DEFAULT 30,\n    parallel_run BOOLEAN DEFAULT TRUE,\n    auto_migration BOOLEAN DEFAULT FALSE,\n    \n    -- Approval and governance\n    approved_by VARCHAR(100),\n    approval_date TIMESTAMPTZ,\n    clinical_sign_off BOOLEAN DEFAULT FALSE,\n    \n    -- Audit\n    created_at TIMESTAMPTZ DEFAULT NOW(),\n    completed_at TIMESTAMPTZ,\n    \n    FOREIGN KEY (old_guideline_id) REFERENCES guidelines(guideline_id),\n    FOREIGN KEY (new_guideline_id) REFERENCES guidelines(guideline_id)\n);\n\nCREATE INDEX idx_transitions_date ON guideline_transitions(transition_date DESC);\nCREATE INDEX idx_transitions_type ON guideline_transitions(change_type);\nCREATE INDEX idx_transitions_impact ON guideline_transitions(clinical_impact_score DESC);\n\n-- =============================================================================\n-- CROSS-KB LINKAGE VALIDATION\n-- =============================================================================\n\n-- Track and validate links to other knowledge bases\nCREATE TABLE kb_linkages (\n    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n    linkage_id VARCHAR(200) UNIQUE NOT NULL,\n    \n    -- Source reference\n    source_guideline VARCHAR(100) NOT NULL,\n    source_rec_id VARCHAR(100) NOT NULL,\n    \n    -- Target KB reference\n    target_kb VARCHAR(20) NOT NULL CHECK (target_kb IN ('KB-1', 'KB-2', 'KB-4', 'KB-5', 'KB-6', 'KB-7')),\n    target_id VARCHAR(100) NOT NULL,\n    link_type VARCHAR(50) NOT NULL CHECK (link_type IN (\n        'dosing', 'interaction', 'monitoring', 'contraindication', 'alternative'\n    )),\n    \n    -- Validation tracking\n    validation_status VARCHAR(20) DEFAULT 'pending' CHECK (validation_status IN (\n        'pending', 'valid', 'invalid', 'broken', 'deprecated'\n    )),\n    last_validated TIMESTAMPTZ,\n    validation_errors JSONB,\n    validation_score INTEGER CHECK (validation_score >= 0 AND validation_score <= 100),\n    \n    -- Link metadata\n    link_strength VARCHAR(20) DEFAULT 'normal' CHECK (link_strength IN ('weak', 'normal', 'strong', 'critical')),\n    bidirectional BOOLEAN DEFAULT FALSE,\n    \n    -- Audit\n    created_at TIMESTAMPTZ DEFAULT NOW(),\n    updated_at TIMESTAMPTZ DEFAULT NOW(),\n    \n    UNIQUE(source_guideline, source_rec_id, target_kb, target_id)\n);\n\nCREATE INDEX idx_kb_linkages_source ON kb_linkages(source_guideline, source_rec_id);\nCREATE INDEX idx_kb_linkages_target ON kb_linkages(target_kb, target_id);\nCREATE INDEX idx_kb_linkages_validation ON kb_linkages(validation_status, last_validated);\nCREATE INDEX idx_kb_linkages_type ON kb_linkages(link_type);\n\n-- =============================================================================\n-- MONITORING AND METRICS\n-- =============================================================================\n\n-- Performance and usage metrics\nCREATE TABLE kb3_metrics (\n    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n    metric_name VARCHAR(100) NOT NULL,\n    metric_value NUMERIC NOT NULL,\n    metric_unit VARCHAR(50),\n    labels JSONB,\n    timestamp TIMESTAMPTZ DEFAULT NOW(),\n    \n    -- Aggregation info\n    aggregation_period VARCHAR(20), -- 1m, 5m, 1h, 1d\n    sample_count INTEGER,\n    \n    INDEX idx_metrics_name_timestamp (metric_name, timestamp DESC),\n    INDEX idx_metrics_timestamp (timestamp DESC)\n);\n\n-- Clinical quality metrics\nCREATE TABLE clinical_quality_metrics (\n    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n    date DATE DEFAULT CURRENT_DATE,\n    \n    -- Guideline currency\n    total_guidelines INTEGER,\n    current_guidelines INTEGER,\n    outdated_guidelines INTEGER,\n    currency_rate NUMERIC(5,4),\n    \n    -- Evidence quality\n    avg_evidence_score NUMERIC(5,2),\n    grade_a_percentage NUMERIC(5,4),\n    grade_b_percentage NUMERIC(5,4),\n    grade_c_percentage NUMERIC(5,4),\n    \n    -- Conflict resolution\n    total_conflicts INTEGER,\n    resolved_conflicts INTEGER,\n    pending_conflicts INTEGER,\n    manual_review_conflicts INTEGER,\n    resolution_rate NUMERIC(5,4),\n    \n    -- Safety overrides\n    safety_overrides_applied INTEGER,\n    critical_overrides INTEGER,\n    emergency_protocols_activated INTEGER,\n    \n    -- Cross-KB validation\n    total_kb_links INTEGER,\n    valid_kb_links INTEGER,\n    broken_kb_links INTEGER,\n    link_validation_rate NUMERIC(5,4),\n    \n    created_at TIMESTAMPTZ DEFAULT NOW(),\n    \n    UNIQUE(date)\n);\n\n-- =============================================================================\n-- AUDIT AND COMPLIANCE\n-- =============================================================================\n\n-- Comprehensive audit log for all KB-3 operations\nCREATE TABLE audit_log (\n    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n    event_id VARCHAR(200) UNIQUE NOT NULL,\n    timestamp TIMESTAMPTZ DEFAULT NOW(),\n    \n    -- Event classification\n    event_type VARCHAR(100) NOT NULL,\n    event_category VARCHAR(50) NOT NULL CHECK (event_category IN (\n        'guideline_management', 'conflict_resolution', 'safety_override', \n        'system_operation', 'user_action', 'integration'\n    )),\n    severity VARCHAR(20) NOT NULL CHECK (severity IN ('debug', 'info', 'warn', 'error', 'critical')),\n    \n    -- Event details\n    event_data JSONB NOT NULL,\n    affected_entities JSONB,\n    \n    -- Context\n    user_id VARCHAR(100),\n    session_id VARCHAR(100),\n    source_system VARCHAR(100),\n    source_ip INET,\n    \n    -- Integrity and compliance\n    requires_signature BOOLEAN DEFAULT FALSE,\n    digital_signature TEXT,\n    checksum VARCHAR(64),\n    compliance_flags TEXT[],\n    \n    -- Retention and lifecycle\n    retention_period INTERVAL DEFAULT '10 years',\n    archived BOOLEAN DEFAULT FALSE,\n    archive_date TIMESTAMPTZ\n);\n\nCREATE INDEX idx_audit_timestamp ON audit_log(timestamp DESC);\nCREATE INDEX idx_audit_event_type ON audit_log(event_type);\nCREATE INDEX idx_audit_category_severity ON audit_log(event_category, severity);\nCREATE INDEX idx_audit_user ON audit_log(user_id, timestamp DESC);\nCREATE INDEX idx_audit_compliance ON audit_log USING GIN(compliance_flags);\n\n-- =============================================================================\n-- CACHE MANAGEMENT\n-- =============================================================================\n\n-- Cache invalidation tracking\nCREATE TABLE cache_invalidations (\n    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n    cache_key VARCHAR(500) NOT NULL,\n    cache_layer VARCHAR(20) NOT NULL CHECK (cache_layer IN ('L1', 'L2', 'L3', 'CDN')),\n    invalidation_reason VARCHAR(100) NOT NULL,\n    invalidated_at TIMESTAMPTZ DEFAULT NOW(),\n    \n    -- Related entities\n    related_guideline_id VARCHAR(100),\n    related_recommendation_id VARCHAR(100),\n    \n    -- Performance impact\n    cache_hit_rate_before NUMERIC(5,4),\n    cache_hit_rate_after NUMERIC(5,4),\n    performance_impact VARCHAR(20) CHECK (performance_impact IN ('none', 'minor', 'moderate', 'significant')),\n    \n    INDEX idx_cache_invalidation_time (invalidated_at DESC),\n    INDEX idx_cache_key (cache_key),\n    INDEX idx_cache_layer (cache_layer)\n);\n\n-- =============================================================================\n-- FUNCTIONS AND TRIGGERS\n-- =============================================================================\n\n-- Automatic timestamp update trigger\nCREATE OR REPLACE FUNCTION update_updated_at_column()\nRETURNS TRIGGER AS $$\nBEGIN\n    NEW.updated_at = NOW();\n    RETURN NEW;\nEND;\n$$ language 'plpgsql';\n\n-- Apply to relevant tables\nCREATE TRIGGER update_guidelines_updated_at BEFORE UPDATE ON guidelines\n    FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();\n\nCREATE TRIGGER update_kb_linkages_updated_at BEFORE UPDATE ON kb_linkages\n    FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();\n\n-- Checksum generation function\nCREATE OR REPLACE FUNCTION generate_audit_checksum(data JSONB)\nRETURNS TEXT AS $$\nBEGIN\n    RETURN encode(digest(data::TEXT, 'sha256'), 'hex');\nEND;\n$$ LANGUAGE plpgsql;\n\n-- Automatic checksum generation for audit records\nCREATE OR REPLACE FUNCTION set_audit_checksum()\nRETURNS TRIGGER AS $$\nBEGIN\n    NEW.checksum = generate_audit_checksum(to_jsonb(NEW));\n    RETURN NEW;\nEND;\n$$ LANGUAGE plpgsql;\n\nCREATE TRIGGER audit_checksum_trigger BEFORE INSERT ON conflict_resolutions\n    FOR EACH ROW EXECUTE FUNCTION set_audit_checksum();\n\nCREATE TRIGGER audit_log_checksum_trigger BEFORE INSERT ON audit_log\n    FOR EACH ROW EXECUTE FUNCTION set_audit_checksum();\n\n-- =============================================================================\n-- VIEWS FOR COMMON QUERIES\n-- =============================================================================\n\n-- Active guidelines with conflict summary\nCREATE VIEW active_guidelines_summary AS\nSELECT \n    g.guideline_id,\n    g.organization,\n    g.region,\n    g.condition_primary,\n    g.effective_date,\n    g.quality_metrics,\n    \n    -- Conflict statistics\n    COALESCE(conflicts.conflict_count, 0) as total_conflicts,\n    COALESCE(conflicts.resolved_count, 0) as resolved_conflicts,\n    COALESCE(conflicts.pending_count, 0) as pending_conflicts,\n    \n    -- Safety override statistics\n    COALESCE(overrides.override_count, 0) as applicable_overrides,\n    \n    -- Cross-KB link health\n    COALESCE(links.total_links, 0) as total_kb_links,\n    COALESCE(links.valid_links, 0) as valid_kb_links,\n    COALESCE(links.broken_links, 0) as broken_kb_links\n    \nFROM guidelines g\nLEFT JOIN (\n    SELECT \n        COALESCE(guideline_1_id, guideline_2_id) as guideline_id,\n        COUNT(*) as conflict_count,\n        COUNT(*) FILTER (WHERE winning_guideline IS NOT NULL) as resolved_count,\n        COUNT(*) FILTER (WHERE winning_guideline IS NULL) as pending_count\n    FROM conflict_resolutions\n    GROUP BY COALESCE(guideline_1_id, guideline_2_id)\n) conflicts ON conflicts.guideline_id = g.guideline_id\nLEFT JOIN (\n    SELECT \n        unnest(affected_guidelines) as guideline_id,\n        COUNT(*) as override_count\n    FROM safety_overrides\n    WHERE active = TRUE\n    GROUP BY unnest(affected_guidelines)\n) overrides ON overrides.guideline_id = g.guideline_id\nLEFT JOIN (\n    SELECT \n        source_guideline,\n        COUNT(*) as total_links,\n        COUNT(*) FILTER (WHERE validation_status = 'valid') as valid_links,\n        COUNT(*) FILTER (WHERE validation_status IN ('invalid', 'broken')) as broken_links\n    FROM kb_linkages\n    GROUP BY source_guideline\n) links ON links.source_guideline = g.guideline_id\nWHERE g.status = 'active';\n\n-- Recent conflict resolutions for monitoring\nCREATE VIEW recent_conflict_resolutions AS\nSELECT \n    cr.conflict_id,\n    cr.timestamp,\n    cr.conflict_type,\n    cr.severity,\n    cr.resolution_rule,\n    cr.confidence_score,\n    cr.safety_override,\n    g1.organization as org1,\n    g2.organization as org2,\n    g1.region as region1,\n    g2.region as region2\nFROM conflict_resolutions cr\nJOIN guidelines g1 ON g1.guideline_id = cr.guideline_1_id\nJOIN guidelines g2 ON g2.guideline_id = cr.guideline_2_id\nWHERE cr.timestamp > NOW() - INTERVAL '7 days'\nORDER BY cr.timestamp DESC;\n\n-- Safety override application summary\nCREATE VIEW safety_override_summary AS\nSELECT \n    so.override_id,\n    so.priority,\n    so.condition,\n    so.description,\n    COUNT(soa.id) as application_count,\n    COUNT(soa.id) FILTER (WHERE soa.requires_immediate_action) as emergency_count,\n    COUNT(soa.id) FILTER (WHERE soa.applied_at > NOW() - INTERVAL '24 hours') as recent_applications,\n    MAX(soa.applied_at) as last_applied\nFROM safety_overrides so\nLEFT JOIN safety_override_audit soa ON soa.override_id = so.override_id\nWHERE so.active = TRUE\nGROUP BY so.override_id, so.priority, so.condition, so.description\nORDER BY so.priority ASC;\n\n-- =============================================================================\n-- INITIAL DATA POPULATION\n-- =============================================================================\n\n-- Insert initial safety overrides\nINSERT INTO safety_overrides (\n    override_id, priority, condition, description, \n    trigger_conditions, override_action, affected_guidelines,\n    requires_audit, active, created_by, approved_by, approval_date\n) VALUES \n(\n    'SAFETY-001', 1, 'hyperkalemia', \n    'Critical hyperkalemia contraindication for RAAS inhibitors',\n    '{\n        \"lab_thresholds\": {\n            \"potassium\": {\"operator\": \">\", \"value\": 6.0, \"unit\": \"mmol/L\", \"critical\": true}\n        },\n        \"conditions\": [\"acute_kidney_injury\", \"hyperkalemic_periodic_paralysis\"]\n    }',\n    '{\n        \"action_type\": \"contraindicate\",\n        \"description\": \"Immediately discontinue RAAS inhibitors\",\n        \"alternatives\": [\"calcium_channel_blockers\", \"beta_blockers\", \"diuretics_thiazide\"],\n        \"monitoring_requirements\": [\"daily_potassium_monitoring\", \"renal_function_q24h\"],\n        \"emergency_protocols\": [\"HYPERKALEMIA_EMERGENCY_PROTOCOL\"]\n    }',\n    ARRAY['ACC-AHA-HTN-2017', 'KDIGO-CKD-2024', 'ESC-HF-2021'],\n    TRUE, TRUE, 'system', 'medical_director', NOW()\n),\n(\n    'SAFETY-002', 1, 'pregnancy',\n    'Teratogenic medication contraindication in pregnancy',\n    '{\n        \"conditions\": [\"pregnancy_confirmed\", \"pregnancy_suspected\", \"breastfeeding\"],\n        \"special_populations\": [\"pregnancy\"]\n    }',\n    '{\n        \"action_type\": \"contraindicate\",\n        \"description\": \"Avoid teratogenic antihypertensive medications\",\n        \"alternatives\": [\"methyldopa\", \"labetalol\", \"nifedipine_immediate_release\"],\n        \"monitoring_requirements\": [\"fetal_monitoring\", \"maternal_bp_daily\"]\n    }',\n    ARRAY['ACC-AHA-HTN-2017', 'ESC-HTN-2023'],\n    TRUE, TRUE, 'system', 'medical_director', NOW()\n),\n(\n    'SAFETY-003', 2, 'severe_renal_impairment',\n    'Severe CKD dose adjustment requirements',\n    '{\n        \"lab_thresholds\": {\n            \"egfr\": {\"operator\": \"<\", \"value\": 30, \"unit\": \"mL/min/1.73m2\"}\n        },\n        \"conditions\": [\"ckd_stage_4\", \"ckd_stage_5\", \"dialysis\"]\n    }',\n    '{\n        \"action_type\": \"modify_dose\",\n        \"description\": \"Reduce dose by 50% or contraindicate if eGFR <15\",\n        \"dose_modifications\": [\n            {\"medication_class\": \"ace_inhibitors\", \"modification_type\": \"reduce\", \"percentage\": 50},\n            {\"medication_class\": \"arbs\", \"modification_type\": \"reduce\", \"percentage\": 50}\n        ],\n        \"monitoring_requirements\": [\"weekly_renal_function\", \"electrolyte_monitoring\"]\n    }',\n    ARRAY['KDIGO-CKD-2024', 'ACC-AHA-HTN-2017'],\n    TRUE, TRUE, 'system', 'clinical_lead', NOW()\n);\n\n-- =============================================================================\n-- PERMISSIONS AND SECURITY\n-- =============================================================================\n\n-- Create roles for different access levels\nCREATE ROLE kb3_reader;\nCREATE ROLE kb3_writer;\nCREATE ROLE kb3_admin;\nCREATE ROLE kb3_clinical_admin;\n\n-- Grant appropriate permissions\n-- Readers: can query guidelines and view audit logs\nGRANT SELECT ON ALL TABLES IN SCHEMA guideline_evidence TO kb3_reader;\nGRANT USAGE ON SCHEMA guideline_evidence TO kb3_reader;\n\n-- Writers: can update non-critical data\nGRANT SELECT, INSERT, UPDATE ON guidelines, kb_linkages, kb3_metrics TO kb3_writer;\nGRANT SELECT ON ALL TABLES IN SCHEMA guideline_evidence TO kb3_writer;\nGRANT USAGE ON SCHEMA guideline_evidence TO kb3_writer;\n\n-- Clinical admins: can manage safety overrides and approve guidelines\nGRANT ALL PRIVILEGES ON ALL TABLES IN SCHEMA guideline_evidence TO kb3_clinical_admin;\nGRANT USAGE ON SCHEMA guideline_evidence TO kb3_clinical_admin;\n\n-- System admins: full access\nGRANT ALL PRIVILEGES ON SCHEMA guideline_evidence TO kb3_admin;\nGRANT ALL PRIVILEGES ON ALL TABLES IN SCHEMA guideline_evidence TO kb3_admin;\n\n-- =============================================================================\n-- MAINTENANCE PROCEDURES\n-- =============================================================================\n\n-- Procedure to archive old audit records\nCREATE OR REPLACE FUNCTION archive_old_audit_records(retention_months INTEGER DEFAULT 120)\nRETURNS INTEGER AS $$\nDECLARE\n    archived_count INTEGER;\nBEGIN\n    UPDATE audit_log \n    SET archived = TRUE, archive_date = NOW()\n    WHERE timestamp < NOW() - (retention_months || ' months')::INTERVAL\n      AND archived = FALSE;\n    \n    GET DIAGNOSTICS archived_count = ROW_COUNT;\n    \n    INSERT INTO audit_log (event_type, event_category, severity, event_data)\n    VALUES (\n        'audit_archival_completed', 'system_operation', 'info',\n        jsonb_build_object('archived_records', archived_count, 'retention_months', retention_months)\n    );\n    \n    RETURN archived_count;\nEND;\n$$ LANGUAGE plpgsql;\n\n-- Procedure to update daily clinical quality metrics\nCREATE OR REPLACE FUNCTION update_clinical_quality_metrics()\nRETURNS VOID AS $$\nBEGIN\n    INSERT INTO clinical_quality_metrics (\n        date, total_guidelines, current_guidelines, outdated_guidelines,\n        currency_rate, avg_evidence_score, grade_a_percentage,\n        total_conflicts, resolved_conflicts, pending_conflicts,\n        resolution_rate, total_kb_links, valid_kb_links, broken_kb_links,\n        link_validation_rate\n    )\n    SELECT \n        CURRENT_DATE,\n        \n        -- Guideline metrics\n        COUNT(*) as total_guidelines,\n        COUNT(*) FILTER (WHERE effective_date > NOW() - INTERVAL '2 years') as current_guidelines,\n        COUNT(*) FILTER (WHERE effective_date <= NOW() - INTERVAL '2 years') as outdated_guidelines,\n        COUNT(*) FILTER (WHERE effective_date > NOW() - INTERVAL '2 years')::NUMERIC / COUNT(*)::NUMERIC as currency_rate,\n        \n        -- Evidence quality (placeholder - would need recommendation table)\n        80.5 as avg_evidence_score,\n        0.65 as grade_a_percentage,\n        \n        -- Conflict metrics\n        (SELECT COUNT(*) FROM conflict_resolutions WHERE timestamp > CURRENT_DATE - INTERVAL '1 day') as total_conflicts,\n        (SELECT COUNT(*) FROM conflict_resolutions WHERE winning_guideline IS NOT NULL AND timestamp > CURRENT_DATE - INTERVAL '1 day') as resolved_conflicts,\n        (SELECT COUNT(*) FROM conflict_resolutions WHERE winning_guideline IS NULL AND timestamp > CURRENT_DATE - INTERVAL '1 day') as pending_conflicts,\n        (SELECT COUNT(*) FILTER (WHERE winning_guideline IS NOT NULL)::NUMERIC / NULLIF(COUNT(*), 0)::NUMERIC FROM conflict_resolutions WHERE timestamp > CURRENT_DATE - INTERVAL '1 day') as resolution_rate,\n        \n        -- Cross-KB link metrics\n        (SELECT COUNT(*) FROM kb_linkages) as total_kb_links,\n        (SELECT COUNT(*) FROM kb_linkages WHERE validation_status = 'valid') as valid_kb_links,\n        (SELECT COUNT(*) FROM kb_linkages WHERE validation_status IN ('invalid', 'broken')) as broken_kb_links,\n        (SELECT COUNT(*) FILTER (WHERE validation_status = 'valid')::NUMERIC / NULLIF(COUNT(*), 0)::NUMERIC FROM kb_linkages) as link_validation_rate\n        \n    FROM guidelines\n    WHERE status = 'active'\n    ON CONFLICT (date) DO UPDATE SET\n        total_guidelines = EXCLUDED.total_guidelines,\n        current_guidelines = EXCLUDED.current_guidelines,\n        currency_rate = EXCLUDED.currency_rate,\n        total_conflicts = EXCLUDED.total_conflicts,\n        resolved_conflicts = EXCLUDED.resolved_conflicts,\n        resolution_rate = EXCLUDED.resolution_rate;\nEND;\n$$ LANGUAGE plpgsql;\n\n-- =============================================================================\n-- INITIAL SETUP VALIDATION\n-- =============================================================================\n\n-- Verify schema creation\nSELECT \n    schemaname,\n    tablename,\n    tableowner\nFROM pg_tables \nWHERE schemaname = 'guideline_evidence'\nORDER BY tablename;\n\n-- Verify indexes\nSELECT \n    schemaname,\n    tablename,\n    indexname,\n    indexdef\nFROM pg_indexes \nWHERE schemaname = 'guideline_evidence'\nORDER BY tablename, indexname;